<span class="line"><span style="color:#A6ACCD;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#A6ACCD;">(imgUrl) </span><span style="color:#676E95;font-style:italic;">// 源文件信息</span></span>
